    @JavascriptInterface
    fun showToast(message: String) {
        scope.launch {
            Toast.makeText(activity, message, Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun openCamera() {
        scope.launch {
            if (checkPermission(android.Manifest.permission.CAMERA)) {
                val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
                activity.startActivityForResult(intent, cameraRequestCode)
            } else {
                requestPermission(android.Manifest.permission.CAMERA, cameraRequestCode)
            }
        }
    }

    @JavascriptInterface
    fun saveToLocalStorage(key: String, value: String) {
        scope.launch {
            val prefs = activity.getSharedPreferences("webapp", Context.MODE_PRIVATE)
            prefs.edit().putString(key, value).apply()
        }
    }

    @JavascriptInterface
    fun getFromLocalStorage(key: String): String {
        val prefs = activity.getSharedPreferences("webapp", Context.MODE_PRIVATE)
        return prefs.getString(key, "") ?: ""
    }

    @JavascriptInterface
    fun subscribePushTopic(topic: String) {
        scope.launch {
            try {
                val token = Tasks.await(FirebaseMessaging.getInstance().token)
                // In a real implementation, you would send this to your backend
                // to register for push notifications
                webView.post {
                    webView.evaluateJavascript("window.onPushTokenReceived('$token')", null)
                }
            } catch (e: ExecutionException) {
                e.printStackTrace()
            } catch (e: InterruptedException) {
                e.printStackTrace()
            }
        }
    }

    @JavascriptInterface
    fun requestPushPermission() {
        scope.launch {
            if (checkPermission(android.Manifest.permission.POST_NOTIFICATIONS)) {
                webView.post {
                    webView.evaluateJavascript("window.onPushPermissionGranted()", null)
                }
            } else {
                requestPermission(android.Manifest.permission.POST_NOTIFICATIONS, 1003)
            }
        }
    }

    private fun checkPermission(permission: String): Boolean {
        return ContextCompat.checkSelfPermission(activity, permission) == PERMISSION_GRANTED
    }

    private fun requestPermission(permission: String, requestCode: Int) {
        val permissions = arrayOf(permission)
        activity.requestPermissions(permissions, requestCode)
    }

    @JavascriptInterface
    fun openUrl(url: String) {
        scope.launch {
            val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
            activity.startActivity(intent)
        }
    }

    @JavascriptInterface
    fun shareText(text: String) {
        scope.launch {
            val shareIntent = Intent().apply {
                action = Intent.ACTION_SEND
                putExtra(Intent.EXTRA_TEXT, text)
                type = "text/plain"
            }
            activity.startActivity(Intent.createChooser(shareIntent, "Share via"))
        }
    }

    private inner class HybridWebViewClient : WebViewClient() {
        override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
