                    },
                    openUrl: function(url) {
                        AndroidBridge.openUrl(url);
                    },
                    shareText: function(text) {
                        AndroidBridge.shareText(text);
                    }
                };
            """.trimIndent()
            view?.evaluateJavascript(js, null)
        }
    }

    private inner class HybridWebChromeClient : WebChromeClient() {
